import { BrowserRouter, Routes, Route } from "react-router-dom";
import Navbar from "./components/Navbar";
import CodeUpload from "./pages/Analysis/CodeUpload";
import Overview from "./pages/Dashboard/Overview";

export default function App() {
    return (
        <BrowserRouter>
            <div className="app">
                <Navbar />
                <main>
                    <Routes>
                        <Route path="/" element={<Overview />} />
                        <Route path="/analysis/upload" element={<CodeUpload />} />
                        {/* Fallback to CodeUpload for missing pages for now */}
                        <Route path="/analysis/pipeline" element={<CodeUpload />} />
                        <Route path="/vulnerabilities/summary" element={<CodeUpload />} />
                        <Route path="/ai/confidence" element={<CodeUpload />} />
                        <Route path="/reports/executive" element={<CodeUpload />} />
                        <Route path="/settings/config" element={<CodeUpload />} />
                    </Routes>
                </main>
            </div>
        </BrowserRouter>
    );
}
